solution_code:
#include <iostream>

int& minimum(int& a, int& b, int& c) {
    if (a <= b && a <= c) return a;
    if (b <= c)           return b;
    return c;
}

int main() {
    int a {}, b {}, c {};
    std::cin >> a >> b >> c;

    minimum(a, b, c) += 1;

    std::cout << "a: " << a << '\n';
    std::cout << "b: " << b << '\n';
    std::cout << "c: " << c << '\n';
    return 0;
}

