solution_code:
#include <iostream>

int* findFirstPositive(int* a, int* b, int* c) {
    if (*a > 0) return a;
    if (*b > 0) return b;
    if (*c > 0) return c;
    return nullptr;
}

int main() {
    int a {}, b {}, c {};
    std::cin >> a >> b >> c;

    int* result { findFirstPositive(&a, &b, &c) };
    if (result == nullptr)
        std::cout << "None\n";
    else
        std::cout << "Found: " << *result << '\n';
    return 0;
}
